import React from 'react'
import Template from './Template'

const Signup = ({setIsLoggedIn}) => {
  return (
    <div>
        <Template
            formtype="signup"
            setIsLoggedIn={setIsLoggedIn}
        />
    </div>
  )
}

export default Signup
